        val nameX = x + 54f
        val namePaint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
            color = colorNavy
            textSize = 20f
            typeface = Typeface.create(Typeface.DEFAULT, Typeface.BOLD)
        }
        canvas.drawText("Pro Painters", nameX, y + 18f, namePaint)

        val subPaint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
